import React from 'react'
import { css } from '@linaria/core'
import ErrorBoundary from '@fs/zion-error-boundary'
import { Observable } from '@fs/zion-frontend-friends'
import { DraggingCursorProvider } from '@fs/zion-ui-draggable'
import { PageWidthProvider, ResponsiveProvider } from '../responsive'
import { FocusManagerProvider } from '../use-focus-manager'
import { ClickAwayProvider } from '../use-click-away'
import { KeyboardShortcutsProvider } from '../use-keyboard-shortcuts'
import { PortalContext, PopperPortalContext, usePortalRef } from '../portal'
import { GridStart } from '../grid'

export const portalsCss = css`
  position: absolute;
  inset: 0;
  pointer-events: none;
  & > * {
    pointer-events: auto;
  }
`

export const fullHeightCss = css`
  display: flex;
  flex-direction: column;
  flex-grow: 1;
`

const containerCss = css`
  position: relative;
  display: flex;
  flex-direction: column;
  flex-grow: 1;
`

export default function GuidancePanelProviders({ children, ...rest }) {
  const [overlayRef, overlaysDiv] = usePortalRef() // although not advertised, we all for limited overlays (like tooltip) in the panel

  return (
    <ErrorBoundary>
      <FocusManagerProvider>
        <ClickAwayProvider>
          <KeyboardShortcutsProvider>
            <DraggingCursorProvider>
              <PageWidthProvider>
                <PortalContext.Provider value={overlaysDiv}>
                  <PopperPortalContext.Provider value={overlaysDiv}>
                    {/* Wrapper div creates positioning context for both content and portals */}
                    <div className={containerCss} {...rest}>
                      {/* The providers below control app height and need the fullHeightCss if they are not already a flex container */}
                      <Observable
                        rootMargin="100%"
                        style={{ position: 'relative', zIndex: 0 }}
                        className={fullHeightCss}
                      >
                        <ResponsiveProvider className={fullHeightCss}>
                          <GridStart className={fullHeightCss}>{children}</GridStart>
                        </ResponsiveProvider>
                      </Observable>
                      <div className={portalsCss}>
                        <div portal="overlays" ref={overlayRef} />
                      </div>
                    </div>
                  </PopperPortalContext.Provider>
                </PortalContext.Provider>
              </PageWidthProvider>
            </DraggingCursorProvider>
          </KeyboardShortcutsProvider>
        </ClickAwayProvider>
      </FocusManagerProvider>
    </ErrorBoundary>
  )
}
