import type { ReactNode } from 'react'
import React, { useContext, createContext, useMemo, useEffect, Suspense } from 'react'
import { css } from '@linaria/core'
import { animated, useSpring } from '@react-spring/web'
import { boolAttr } from '@fs/zion-frontend-friends'
import { useInfoSheet, colors, GuidancePanelProviders, useContainerWidth } from '@fs/zion-ui'
import { type IconComponent } from '@fs/zion-icon'
import ErrorBoundary from '@fs/zion-error-boundary'
import GuidancePanel from './GuidancePanel'

const guidancePanelLayoutCss = css`
  display: flex;
  transition: background-color 0.3s ease;

  &[data-panel-open] {
    background-color: ${colors.gray02};
  }
`

const mainContentCss = css`
  position: relative; /* Establish a position for portals */
  flex: 1; /* Take up available space in the flex container */
  height: calc(
    var(--visual-viewport-height) - var(--virtual-keyboard-height, 0px)
  ); // Without an explicit height on mainContentCss, it would grow to fit its content (the scrollable Observable container)
  display: flex;
  flex-direction: column;
  transition:
    border-radius 0.3s ease,
    margin 0.3s ease,
    border 0.3s ease;

  &[data-panel-open] {
    border-start-end-radius: var(--guidance-panel-border-radius, 12px);
    border-top: 1px solid var(--gray05);
    border-inline-end: 1px solid var(--gray05);
    margin-top: var(--spacer-xxs);
    height: calc(
      var(--visual-viewport-height) - var(--spacer-xxs) - var(--virtual-keyboard-height, 0px)
    ); // needed to keep the container "sticky"
    overflow: hidden;
  }
`

export const GuidancePanelContext = createContext<GuidancePanelProviderValues | null>(null)

type GuidancePanelProviderValues = {
  panelPortalDiv: Element | null
  isMobile: boolean
  infoSheetConfig: ReturnType<typeof useInfoSheet>
  title: string
  headerIcon?: IconComponent
  headerActions?: ReactNode
  contentComponent?: React.ComponentType
  footerContent?: ReactNode
}

export type GuidancePanelHeaderProps = {
  icon?: IconComponent
  text: string
  actions?: ReactNode
}

export const useGuidancePanelContext = (): GuidancePanelProviderValues | null => {
  return useContext(GuidancePanelContext)
}

const PANEL_WIDTH = 412

/**
 * Provider component that manages the GuidancePanel - a side panel for contextual help, AI assistants, and supporting tools.
 * See the Storybook documentation for full details on usage and behavior.
 */
export const GuidancePanelProvider = ({
  children,
  panelPortalDiv,
  panelPortalRef,
  title,
  headerIcon,
  headerActions,
  contentComponent,
  footerContent,
}: {
  children: ReactNode
  panelPortalDiv: Element | null
  panelPortalRef: (node: HTMLDivElement | null) => void
  title: string
  headerIcon?: IconComponent
  headerActions?: ReactNode
  contentComponent?: React.ComponentType
  footerContent?: ReactNode
}): JSX.Element => {
  const infoSheetConfig = useInfoSheet({
    initiallyBottomSheet: true,
    initialBottomSheetHeight: 1, // 100% height
  })
  const isMobile = useContainerWidth()({ default: true, lg: false })
  const { isOpen, handleTransitioned, transitioning } = infoSheetConfig

  // Spring animation for smooth layout transitions
  const [layoutSpring, layoutApi] = useSpring(() => ({
    spacerWidth: 0,
    config: { tension: 300, friction: 30 },
  }))

  useEffect(() => {
    // Only apply side-by-side layout on desktop (not mobile)
    const effectiveWidth = isOpen && !isMobile ? PANEL_WIDTH : 0

    // Update layout springs
    layoutApi.start({
      spacerWidth: effectiveWidth,
      onRest: () => {
        // Call handleTransitioned after animation completes (desktop only)
        // Mobile uses ModalInfoSheet which handles this itself
        if (!isMobile) {
          handleTransitioned()
        }
      },
    })

    return () => {
      layoutApi.stop()
    }
  }, [isOpen, isMobile, layoutApi, handleTransitioned])

  const contextValue = useMemo(
    (): GuidancePanelProviderValues => ({
      panelPortalDiv,
      isMobile,
      infoSheetConfig,
      title,
      headerIcon,
      headerActions,
      contentComponent,
      footerContent,
    }),
    [panelPortalDiv, isMobile, infoSheetConfig, title, headerIcon, headerActions, contentComponent, footerContent]
  )

  return (
    <GuidancePanelContext.Provider value={contextValue}>
      {/* Desktop: Render the GuidancePanel as side panel */}
      {/* Mobile: GuidancePanelMobileRenderer should be rendered inside AppContentProviders */}
      {!isMobile && (
        <ErrorBoundary fallback={null}>
          <Suspense fallback={null}>
            <GuidancePanel />
          </Suspense>
        </ErrorBoundary>
      )}

      <div className={guidancePanelLayoutCss} data-panel-open={boolAttr(isOpen && !isMobile)}>
        <div className={mainContentCss} data-panel-open={boolAttr(isOpen && !isMobile)}>
          {children}
        </div>

        {!isMobile && (
          <animated.div
            style={{
              width: layoutSpring.spacerWidth,
              display: isOpen || transitioning ? 'block' : 'none',
            }}
          >
            <GuidancePanelProviders>
              <div ref={panelPortalRef} data-guidance-panel-portal />
            </GuidancePanelProviders>
          </animated.div>
        )}
      </div>
    </GuidancePanelContext.Provider>
  )
}
