import React, { useRef, useEffect } from 'react'
import { css } from '@linaria/core'
import { createPortal } from 'react-dom'
import { useTranslation } from 'react-i18next'
import { useMountedRef } from '@fs/zion-frontend-friends'
import { colors, LayoutBand, Row, H2, IconButton } from '@fs/zion-ui'
import { MenuClose, type IconComponent } from '@fs/zion-icon'
import { useGuidancePanelContext } from './GuidancePanelProvider'

const containerCss = css`
  display: flex;
  flex-direction: column;
  width: 412px;
  height: var(--layout-viewport-height);
  padding: var(--spacer-xxs);
`

const cardCss = css`
  flex: 1;
  min-height: 0;
  display: flex;
  flex-direction: column;
  border: 1px solid ${colors.gray05};
  border-radius: var(--spacer-xxs);
  background: ${colors.gray00};
`

const scrollableContentCss = css`
  flex: 1;
  min-height: 0;
  overflow-y: auto;
  padding: var(--spacer-xs);
`

type GuidancePanelHeaderInternalProps = {
  icon?: IconComponent
  text: string
  actions?: React.ReactNode
  onClose: () => void
  headerRef: React.RefObject<HTMLDivElement>
}

function GuidancePanelHeaderInternal({
  icon: Icon,
  text,
  actions,
  onClose,
  headerRef,
}: GuidancePanelHeaderInternalProps): JSX.Element {
  const { t } = useTranslation()

  return (
    <div ref={headerRef} tabIndex={-1} style={{ outline: 'none' }} role="group" aria-live="polite" aria-atomic="true">
      <LayoutBand
        marginY="xs"
        minHeight="60px" // same minHeight as the GlobalHeader2019
        marginX="xs"
        style={{ borderBottom: '1px solid var(--gray10)' }}
      >
        <Row alignY="middle" gutters="xs">
          <Row alignY="middle" gutters="pico" growX noShrinkX>
            {Icon && <Icon size="xs" />}
            <H2 id="guidance-panel-title" size="H6">
              {text}
            </H2>
          </Row>
          {actions}
          <IconButton
            title={t('common-ui:close.action', 'Close')}
            aria-label={t('common-ui:close.action', 'Close')}
            onClick={onClose}
            Icon={MenuClose}
            color="gray"
            size="xs"
          />
        </Row>
      </LayoutBand>
    </div>
  )
}

function GuidancePanelFooterInternal({ children }: { children: React.ReactNode }): JSX.Element {
  return (
    <LayoutBand marginY="xs" marginX="xs">
      {children}
    </LayoutBand>
  )
}

export default function GuidancePanel(): JSX.Element | null {
  const context = useGuidancePanelContext()
  const headerRef = useRef<HTMLDivElement>(null)
  const mountedRef = useMountedRef()
  if (!context) throw new Error('GuidancePanel must be used within a GuidancePanelProvider')

  const {
    infoSheetConfig: { isOpen, close },
    isMobile,
    panelPortalDiv,
    title,
    headerIcon,
    headerActions,
    contentComponent: ContentComponent,
    footerContent,
  } = context

  // Focus the header when opened (desktop only)
  useEffect(() => {
    if (!isOpen || isMobile) return

    requestAnimationFrame(() => {
      // Check if component is still mounted before focusing
      if (mountedRef.current) {
        headerRef.current?.focus({ preventScroll: true })
      }
    })
  }, [isOpen, isMobile, mountedRef])

  // Mobile: Render only content (ModalInfoSheet provides header/footer)
  if (isMobile) {
    return ContentComponent ? <ContentComponent /> : null
  }

  // Desktop: Shared content component
  const PanelContent = (
    <>
      <GuidancePanelHeaderInternal
        icon={headerIcon}
        text={title}
        actions={headerActions}
        onClose={close}
        headerRef={headerRef}
      />
      <div className={scrollableContentCss}>{ContentComponent && <ContentComponent />}</div>
      {footerContent && <GuidancePanelFooterInternal>{footerContent}</GuidancePanelFooterInternal>}
    </>
  )

  // Desktop: Render as side panel via portal
  if (!panelPortalDiv) return null

  return createPortal(
    <div className={containerCss}>
      {/* This is a non-modal dialog for now because we want to interact with the GuidancePanel when a DialogOverlay is open. Eventually we should change this to role=complementary if we change the architecture of apps */}
      <div className={cardCss} aria-modal="false" role="dialog" aria-labelledby="guidance-panel-title">
        {PanelContent}
      </div>
    </div>,
    panelPortalDiv
  )
}
