import React from 'react'
import { IconButton } from '@fs/zion-ui'
import { css } from '@linaria/core'
import { HelpAi } from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'
import { useGuidancePanelContext } from './GuidancePanelProvider'

// Right now I have it as a FAB, but in the future we may move it into the header
const stickyButtonCss = css`
  position: sticky;
  bottom: 0;
  inset-inline-end: 0;
  z-index: 2;

  button {
    position: absolute;
    bottom: var(--spacer-sm);
    inset-inline-end: var(--spacer-sm);
  }
`

export default function GuidancePanelLaunchButton(): JSX.Element {
  const context = useGuidancePanelContext()
  const { t } = useTranslation()

  if (!context) {
    throw new Error('GuidancePanelLaunchButton must be used within a GuidancePanelProvider')
  }

  const { handleClick } = context.infoSheetConfig

  return (
    <div className={stickyButtonCss}>
      <IconButton
        Icon={HelpAi}
        title={t('common-ui:open.action', 'Open')}
        onClick={handleClick}
        size="md"
        color="gray"
        emphasis="lightHigh"
      />
    </div>
  )
}
