import React, { Suspense } from 'react'
import { useTranslation } from 'react-i18next'
import { ModalInfoSheet, LayoutBand, Row } from '@fs/zion-ui'
import ErrorBoundary from '@fs/zion-error-boundary'
import { useGuidancePanelContext } from './GuidancePanelProvider'
import GuidancePanel from './GuidancePanel'

/**
 * This component must be rendered inside AppContentProviders (in the main content area)
 * so that ModalInfoSheet has access to InfoSheetProvider and other required providers.
 */
export default function GuidancePanelMobileRenderer(): JSX.Element | null {
  const context = useGuidancePanelContext()
  const { t } = useTranslation()

  if (!context || !context.isMobile) return null

  const { infoSheetConfig, title, footerContent } = context

  // Wrap footer content with same layout as desktop
  const footer = footerContent ? (
    <LayoutBand marginY="xs" marginX="xs">
      <Row gutters="nano">{footerContent}</Row>
    </LayoutBand>
  ) : undefined

  return (
    <ModalInfoSheet
      size="md"
      title={title || ''}
      closeLabel={t('common-ui:close.action', 'Close')}
      footer={footer}
      {...infoSheetConfig}
    >
      <ErrorBoundary fallback={null}>
        <Suspense fallback={null}>
          <GuidancePanel />
        </Suspense>
      </ErrorBoundary>
    </ModalInfoSheet>
  )
}
